schema:
{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "definitions": {
        "poll_answer": {
            "type": "object",
            "description": "Poll answer object for both trivia and normal polls",
            "additionalProperties": false,
            "properties": {
                "id": {
                    "type": "integer"
                },
                "uuid": {
                    "type": "string"
                },
                "title": {
                    "type": "string"
                },
                "correct": {
                    "type": "boolean"
                },
                "un_enum": {
                    "enum": [
                        "apo",
                        "apolo",
                        "apolinares"
                    ]
                }
            },
            "required": [
                "id",
                "uuid",
                "title"
            ]
        },
        "image": {
            "type": "object",
            "properties": {
                "@type": {
                    "type": "string",
                    "enum": [
                        "image"
                    ]
                },
                "cloudinary_id": {
                    "type": "string"
                },
                "caption": {
                    "type": "string"
                },
                "height": {
                    "type": "integer"
                },
                "width": {
                    "type": "integer"
                },
                "original_format": {
                    "type": "string",
                    "enum": [
                        "jpg",
                        "gif",
                        "png",
                        "jpeg"
                    ]
                }
            },
            "required": [
                "@type",
                "cloudinary_id"
            ]
        }
    },
    "title": " Poll",
    "type": "object",
    "description": "Poll object for normal or trivia polls",
    "additionalProperties": false,
    "properties": {
        "@type": {
            "type": "string",
            "enum": [
                "poll"
            ]
        },
        "id": {
            "type": "integer"
        },
        "uuid": {
            "type": "string"
        },
        "@poll_type": {
            "type": "string",
            "enum": [
                "poll",
                "trivia"
            ]
        },
        "title": {
            "type": "string"
        },
        "image": {
            "$ref": "#/definitions/image"
        },
        "answers": {
            "type": "array",
            "items": {
                "$ref": "#/definitions/poll_answer"
            }
        }
    },
    "required": [
        "@type",
        "id",
        "uuid",
        "@poll_type",
        "title",
        "answers"
    ]
}

{
    "definitions": {
        "book": {
            "properties": {
                "authors": {
                    "items": {
                        "type": "string"
                    },
                    "type": "array",
                    "_uniqueItems": true
                },
                "coverFilename": {
                    "type": "string"
                },
                "id": {
                    "type": "string"
                },
                "tags": {
                    "items": {
                        "type": "string"
                    },
                    "type": "array",
                    "_uniqueItems": true
                },
                "title": {
                    "type": "string"
                },
                "url": {
                    "type": "string"
                }
            },
            "required": [
                "id",
                "title",
                "authors",
                "url",
                "tags",
                "coverFilename"
            ],
            "type": "object"
        }
    },
    "properties": {
        "lastBookId": {
            "minimum": -1,
            "type": "integer"
        },
        "list": {
            "items": {
                "$ref": "#/definitions/book"
            },
            "type": "array",
            "_uniqueItems": true
        }
    },
    "required": [
        "lastBookId",
        "list"
    ],
    "type": "object"
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "required": [
        "Type",
        "HttpMethod",
        "ResourceId",
        "RestApiId"
    ],
    "additionalProperties": false,
    "properties": {
        "Type": {
            "type": "string",
            "enum": [
                "HTTP",
                "AWS",
                "MOCK"
            ]
        },
        "HttpMethod": {
            "type": "string",
            "enum": [
                "DELETE",
                "GET",
                "HEAD",
                "OPTIONS",
                "PATCH",
                "POST",
                "PUT"
            ]
        },
        "ResourceId": {
            "type": "string",
            "pattern": "^[a-z0-9]+$"
        },
        "RestApiId": {
            "type": "string",
            "pattern": "^[a-z0-9]{10}$"
        },
        "CacheKeyParameters": {
            "type": "array",
            "items": {
                "type": "string"
            }
        },
        "CacheNamespace": {
            "type": "string"
        },
        "Credentials": {
            "type": "string"
        },
        "IntegrationHttpMethod": {
            "type": "string"
        },
        "RequestTemplates": {
            "type": "object",
            "properties": {},
            "patternProperties": {
                ".+": {
                    "type": "string"
                }
            },
            "additionalProperties": false
        },
        "RequestParameters": {
            "type": "object",
            "properties": {},
            "patternProperties": {
                "^integration\\.request\\.(querystring|path|header)\\..+$": {
                    "type": "string",
                    "pattern": "^(method\\.request\\.(querystring|header|path)\\..+)|('.*')$"
                }
            },
            "additionalProperties": false
        },
        "Uri": {
            "type": "string"
        }
    }
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "required": [
        "DomainName"
    ],
    "properties": {
        "DomainName": {
            "type": "string",
            "pattern": "^[a-z][a-z0-9\\-]+$"
        },
        "AccessPolicies": {
            "type": "string",
            "pattern": ".+"
        },
        "AdvancedOptions": {
            "type": "object",
            "patternProperties": {
                ".+": {
                    "type": "string",
                    "pattern": ".+"
                }
            },
            "additionalProperties": false
        },
        "EBSOptions": {
            "type": "object",
            "properties": {
                "EBSEnabled": {
                    "type": "string",
                    "enum": [
                        "true",
                        "false"
                    ]
                },
                "Iops": {
                    "type": "string",
                    "pattern": "^\\d+$"
                },
                "VolumeSize": {
                    "type": "string",
                    "pattern": "^\\d+$"
                },
                "VolumeType": {
                    "type": "string",
                    "enum": [
                        "standard",
                        "gp2",
                        "io1"
                    ]
                }
            },
            "additionalProperties": false
        },
        "ElasticsearchClusterConfig": {
            "type": "object",
            "properties": {
                "DedicatedMasterCount": {
                    "type": "string",
                    "pattern": "^\\d$"
                },
                "DedicatedMasterEnabled": {
                    "type": "string",
                    "enum": [
                        "true",
                        "false"
                    ]
                },
                "DedicatedMasterType": {
                    "$ref": "#/definitions/ElasticseachNodeType"
                },
                "InstanceCount": {
                    "type": "string",
                    "pattern": "^\\d$"
                },
                "InstanceType": {
                    "$ref": "#/definitions/ElasticseachNodeType"
                },
                "ZoneAwarenessEnabled": {
                    "type": "string",
                    "enum": [
                        "true",
                        "false"
                    ]
                }
            },
            "additionalProperties": false
        },
        "SnapshotOptions": {
            "type": "object",
            "properties": {
                "AutomatedSnapshotStartHour": {
                    "type": "string",
                    "pattern": "^\\d$"
                }
            },
            "additionalProperties": false
        }
    },
    "additionalProperties": false,
    "definitions": {
        "ElasticseachNodeType": {
            "type": "string",
            "enum": [
                "m3.medium.elasticsearch",
                "m3.large.elasticsearch",
                "m3.xlarge.elasticsearch",
                "m3.2xlarge.elasticsearch",
                "t2.micro.elasticsearch",
                "t2.small.elasticsearch",
                "t2.medium.elasticsearch",
                "r3.large.elasticsearch",
                "r3.xlarge.elasticsearch",
                "r3.2xlarge.elasticsearch",
                "r3.4xlarge.elasticsearch",
                "r3.8xlarge.elasticsearch",
                "i2.xlarge.elasticsearch",
                "i2.2xlarge.elasticsearch"
            ]
        }
    }
}

{
    "$schema": "http://json-schema.org/draft-07/schema",
    "title": "Prerender Target",
    "type": "object",
    "properties": {
        "browserTarget": {
            "type": "string",
            "description": "Target to build.",
            "pattern": "^[^:\\s]+:[^:\\s]+(:[^\\s]+)?$"
        },
        "serverTarget": {
            "type": "string",
            "description": "Server target to use for prerendering the app.",
            "pattern": "^[^:\\s]+:[^:\\s]+(:[^\\s]+)?$"
        },
        "routesFile": {
            "type": "string",
            "description": "The path to a file containing routes separated by newlines."
        },
        "routes": {
            "type": "array",
            "description": "The routes to render.",
            "items": {
                "minItems": 1,
                "type": "string",
                "_uniqueItems": true
            },
            "default": []
        },
        "guessRoutes": {
            "type": "boolean",
            "description": "Whether or not the builder should extract routes and guess which paths to render.",
            "default": true
        },
        "numProcesses": {
            "type": "number",
            "description": "The number of cpus to use. Defaults to all but one.",
            "minimum": 1
        }
    },
    "required": [
        "browserTarget",
        "serverTarget"
    ],
    "anyOf": [
        {
            "required": [
                "routes"
            ]
        },
        {
            "required": [
                "routesFile"
            ]
        }
    ],
    "additionalProperties": false
}

{
    "$schema": "http://json-schema.org/draft-07/schema",
    "title": "SSR Dev Server Target",
    "description": "SSR Dev Server target options for Build Facade.",
    "type": "object",
    "properties": {
        "browserTarget": {
            "type": "string",
            "description": "Browser target to build.",
            "pattern": ".+:.+(:.+)?"
        },
        "serverTarget": {
            "type": "string",
            "description": "Server target to build.",
            "pattern": ".+:.+(:.+)?"
        },
        "host": {
            "type": "string",
            "description": "Host to listen on.",
            "default": "localhost"
        },
        "port": {
            "type": "number",
            "default": 4200,
            "description": "Port to start the development server at. Default is 4200. Pass 0 to get a dynamically assigned port."
        },
        "publicHost": {
            "type": "string",
            "description": "The URL that the browser client should use to connect to the development server. Use for a complex dev server setup, such as one with reverse proxies."
        },
        "open": {
            "type": "boolean",
            "description": "Opens the url in default browser.",
            "default": false,
            "alias": "o"
        },
        "progress": {
            "type": "boolean",
            "description": "Log progress to the console while building."
        },
        "inspect": {
            "type": "boolean",
            "description": "Launch the development server in inspector mode and listen on address and port '127.0.0.1:9229'.",
            "default": false
        }
    },
    "additionalProperties": false,
    "required": [
        "browserTarget",
        "serverTarget"
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "properties": {
        "windowSize": {
            "type": "object",
            "properties": {
                "width": {
                    "type": "integer",
                    "default": 1024
                },
                "height": {
                    "type": "integer",
                    "default": 768
                }
            }
        },
        "shotSize": {
            "type": "object",
            "properties": {
                "width": {
                    "type": [
                        "integer",
                        "string"
                    ],
                    "default": 1024
                },
                "height": {
                    "type": [
                        "integer",
                        "string"
                    ],
                    "default": 768
                }
            }
        },
        "shotOffset": {
            "type": "object",
            "properties": {
                "left": {
                    "type": "integer",
                    "default": 0
                },
                "right": {
                    "type": "integer",
                    "default": 0
                },
                "top": {
                    "type": "integer",
                    "default": 0
                },
                "bottom": {
                    "type": "integer",
                    "default": 0
                }
            }
        },
        "phantomConfig": {
            "type": "object",
            "properties": {
                "ignore-ssl-errors": {
                    "type": "string",
                    "default": "false"
                }
            }
        },
        "cookies": {
            "type": "array",
            "items": {}
        },
        "customHeaders": {
            "type": [
                "null",
                "object"
            ],
            "default": null
        },
        "defaultWhiteBackground": {
            "type": "boolean",
            "default": false
        },
        "customCSS": {
            "type": "string",
            "default": ""
        },
        "quality": {
            "type": "integer",
            "default": 75
        },
        "streamType": {
            "type": "string",
            "default": "png"
        },
        "renderDelay": {
            "type": "integer",
            "default": 0
        },
        "timeout": {
            "type": "integer",
            "default": 0
        },
        "takeShotOnCallback": {
            "type": "boolean",
            "default": false
        },
        "errorIfStatusIsNot200": {
            "type": "boolean",
            "default": false
        },
        "errorIfJSException": {
            "type": "boolean",
            "default": false
        },
        "captureSelector": {
            "type": [
                "boolean",
                "string"
            ],
            "default": false
        }
    },
    "oneOf": [
        {
            "properties": {
                "siteType": {
                    "type": "string",
                    "enum": [
                        "url"
                    ]
                },
                "url": {
                    "type": "string",
                    "minLength": 1
                }
            },
            "required": [
                "siteType",
                "url"
            ]
        },
        {
            "properties": {
                "siteType": {
                    "type": "string",
                    "enum": [
                        "html"
                    ]
                },
                "html": {
                    "type": "string",
                    "minLength": 1
                }
            },
            "required": [
                "siteType",
                "html"
            ]
        }
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "Codex Instance Schema",
    "description": "Codex Instance Schema",
    "type": "object",
    "additionalProperties": false,
    "properties": {
        "id": {
            "type": "string",
            "description": "the ID of the original record within its own database: since these come from various sources they may take different forms, e.g. integer, UUID"
        },
        "title": {
            "type": "string",
            "description": "the primary title (or label) associated with the resource"
        },
        "altTitle": {
            "type": "string",
            "description": "an alternative title for the resource. (e.g. original language version title of a movie)"
        },
        "series": {
            "type": "string",
            "description": "a series title associated with the resource (e.g. Harry Potter)"
        },
        "contributor": {
            "type": "array",
            "description": "list of contributors to the resource",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "type": {
                        "type": "string",
                        "description": "type of contributor to the resource"
                    },
                    "name": {
                        "type": "string",
                        "description": "name of contributor to the resource"
                    }
                }
            },
            "additionalItems": true,
            "_uniqueItems": true
        },
        "subject": {
            "type": "array",
            "description": "list of subjects this resource belongs to",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "type": {
                        "type": "string",
                        "description": "type of subject"
                    },
                    "name": {
                        "type": "string",
                        "description": "name of subject"
                    }
                }
            },
            "additionalItems": true,
            "_uniqueItems": true
        },
        "publisher": {
            "type": "string",
            "description": "name of publisher of the resource"
        },
        "date": {
            "type": "string",
            "description": "the date of publication of the resource"
        },
        "type": {
            "type": "string",
            "description": "content type of the resource",
            "enum": [
                "audio",
                "audiobooks",
                "books",
                "bookseries",
                "databases",
                "ebooks",
                "kits",
                "maps",
                "music",
                "newspapers",
                "newsletters",
                "periodicals",
                "posters",
                "reports",
                "proceedings",
                "thesisanddissertation",
                "unspecified",
                "video",
                "webresources"
            ]
        },
        "format": {
            "type": "string",
            "description": "format of the resource"
        },
        "identifier": {
            "type": "array",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "value": {
                        "type": "string",
                        "description": "identifier type : e.g. ISSN"
                    },
                    "type": {
                        "type": "string",
                        "description": "identifier value"
                    }
                }
            },
            "additionalItems": true,
            "_uniqueItems": true,
            "description": "an extensible set of name-value pairs of identifiers associated with the resource"
        },
        "source": {
            "type": "string",
            "description": "a label indicating the source of the recent, e.g. kb, local"
        },
        "language": {
            "type": "array",
            "description": "the set of languages used by the resource",
            "items": {
                "type": "string"
            }
        },
        "rights": {
            "type": "string",
            "description": "access rights associated with the resource"
        },
        "version": {
            "type": "string",
            "description": "version of the resource"
        },
        "lastModified": {
            "type": "string",
            "description": "date/time when this resource was last modified"
        }
    },
    "required": [
        "id",
        "title",
        "type",
        "source"
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "required": [
        "_elements"
    ],
    "properties": {
        "_attributes": {
            "type": "object",
            "required": [
                "extracted"
            ],
            "properties": {
                "extracted": {
                    "type": "boolean"
                }
            }
        },
        "_elements": {
            "type": "array",
            "items": {
                "anyOf": [
                    {
                        "$ref": "#/definitions/file"
                    },
                    {
                        "$ref": "#/definitions/file_remote_dir"
                    }
                ]
            }
        }
    },
    "definitions": {
        "file_common": {
            "type": "object",
            "required": [
                "name",
                "type"
            ],
            "properties": {
                "name": {
                    "type": "string"
                }
            }
        },
        "file": {
            "allOf": [
                {
                    "$ref": "#/definitions/file_common"
                },
                {
                    "properties": {
                        "user": {
                            "type": "string",
                            "minLength": 1
                        },
                        "group": {
                            "type": "string",
                            "minLength": 1
                        }
                    },
                    "oneOf": [
                        {
                            "$ref": "#/definitions/file_file"
                        },
                        {
                            "$ref": "#/definitions/file_dir"
                        },
                        {
                            "$ref": "#/definitions/file_link"
                        }
                    ]
                }
            ]
        },
        "file_file": {
            "properties": {
                "type": {
                    "enum": [
                        "file"
                    ]
                },
                "size": {
                    "type": "integer",
                    "minimum": 0
                },
                "mode": {
                    "type": "string",
                    "pattern": "^[0-7]{3,4}$"
                }
            }
        },
        "file_dir": {
            "properties": {
                "type": {
                    "enum": [
                        "dir"
                    ]
                },
                "size": {
                    "type": "integer",
                    "minimum": 0
                },
                "mode": {
                    "type": "string",
                    "pattern": "^[0-4]?[0-7]{3}$"
                },
                "files": {
                    "type": "integer",
                    "minimum": 0
                }
            }
        },
        "file_link": {
            "properties": {
                "type": {
                    "enum": [
                        "link"
                    ]
                }
            }
        },
        "file_remote_dir": {
            "allOf": [
                {
                    "$ref": "#/definitions/file_common"
                },
                {
                    "properties": {
                        "type": {
                            "enum": [
                                "remote_dir"
                            ]
                        }
                    }
                }
            ]
        }
    }
}

